const data = $input.first().json;
const user = data.user;
const sub = data.subscription;
const reminderType = data.reminder_type;

let subject, body;

if (reminderType === 'payment_failed') {
  subject = 'Action requise - Échec de paiement Tempo Budget';
  body = `Bonjour ${user.name},

Nous n'avons pas pu traiter votre paiement de ${sub.amount_due.toFixed(2)} ${sub.currency} pour votre abonnement Tempo Budget.

Pour éviter une interruption de service, merci de mettre à jour votre moyen de paiement :
https://tempo-finance.com/settings

Si vous avez des questions, n'hésitez pas à nous contacter.

Cordialement,
L'équipe Tempo Budget`;
} else if (reminderType === 'expiring_soon') {
  subject = 'Votre abonnement Tempo Budget expire bientôt';
  body = `Bonjour ${user.name},

Votre abonnement Tempo Budget expire le ${sub.due_date}.

Pour continuer à profiter de toutes les fonctionnalités, renouvelez votre abonnement :
https://tempo-finance.com/settings

Cordialement,
L'équipe Tempo Budget`;
} else {
  subject = 'Renouvellement prochain - Tempo Budget';
  body = `Bonjour ${user.name},

Votre abonnement Tempo Budget sera renouvelé dans ${sub.days_until_due} jour(s).

Montant : ${sub.amount_due.toFixed(2)} ${sub.currency}
Date : ${sub.due_date}

Pour gérer votre abonnement :
https://tempo-finance.com/settings

Cordialement,
L'équipe Tempo Budget`;
}

return { json: { to: user.email, subject, body } };
